return (function(a, b, c, d, e)
    for f = 0, 255 do
        a[b(f, 0)] = b(f)
    end

    function d(f, g, h, i)
        if h > 255 then
            h = 0
            i = i + 1

            if i > 255 then
                g = {}
                i = 1
            end
        end

        g[b(h, i)] = f
        h = h + 1

        return g, h, i
